    const tagName = typeof ctx.staticProps.as === "string" ? ctx.staticProps.as : "div";
    const sx = resolveInlineBaseFlexSx(ctx.staticProps);
    const consumedProps = [...INLINE_BASE_FLEX_CONSUMED_PROPS];

